// CB01-style keyword classification / dispatch matrix
const message = ($json.body.message || '').toLowerCase();
const source = $json.body.source || 'unknown';

// Dispatch matrix: keyword patterns -> agent classification
const dispatchMatrix = [
  { agent: 'lucy', keywords: ['creative', 'design', 'brand', 'visual', 'color', 'logo', 'aesthetic', 'campaign', 'mood board'], model: 'llama3', description: 'Creative Director' },
  { agent: 'voice-engine', keywords: ['voice', 'speak', 'synthesize', 'tts', 'vocal', 'clone', 'speech', 'prosody', 'phoneme'], model: 'llama3', description: 'Voice Synthesis Engine' },
  { agent: 'consent-oracle', keywords: ['consent', 'permission', 'rights', 'license', 'block', 'allow', 'revoke', 'scope'], model: 'mistral', description: 'Consent Oracle' },
  { agent: 'memory-keeper', keywords: ['remember', 'memory', 'echo', 'moment', 'origin', 'story', 'narrative', 'history', 'dream'], model: 'llama3', description: 'Memory Keeper / Echo Engine' },
  { agent: 'code-architect', keywords: ['code', 'build', 'deploy', 'api', 'schema', 'database', 'function', 'worker', 'debug', 'fix'], model: 'codellama', description: 'Code Architect' },
  { agent: 'provenance-signer', keywords: ['provenance', 'manifest', 'sign', 'hash', 'integrity', 'chain', 'verify', 'seal'], model: 'mistral', description: 'Provenance Signer' },
  { agent: 'receipts-clerk', keywords: ['receipt', 'payment', 'split', '75', 'royalty', 'payout', 'revenue', 'settlement'], model: 'mistral', description: 'Receipts Clerk (75/25)' },
  { agent: 'general', keywords: [], model: 'mixtral', description: 'General Assistant (fallback)' }
];

// Score each agent by keyword match count
let bestMatch = dispatchMatrix[dispatchMatrix.length - 1]; // default to general
let bestScore = 0;

for (const entry of dispatchMatrix) {
  const score = entry.keywords.filter(kw => message.includes(kw)).length;
  if (score > bestScore) {
    bestScore = score;
    bestMatch = entry;
  }
}

return [
  {
    json: {
      original_message: $json.body.message,
      source: source,
      classification: bestMatch.agent,
      agent_description: bestMatch.description,
      model: bestMatch.model,
      confidence: bestScore > 0 ? Math.min(bestScore / 3, 1.0) : 0.1,
      matched_keywords: bestMatch.keywords.filter(kw => message.includes(kw)),
      classified_at: new Date().toISOString()
    }
  }
];

