parameters.functionCode:
// Log routing decision to master-command-log format
const classification = $node["Function: Keyword Classification"].json;
const agentResponse = $json.message ? $json.message.content : ($json.response || 'No response');

const logEntry = {
  log_type: "agent-route",
  timestamp: new Date().toISOString(),
  source: classification.source,
  message_preview: classification.original_message.substring(0, 100),
  routed_to: classification.classification,
  agent_description: classification.agent_description,
  model: classification.model,
  confidence: classification.confidence,
  matched_keywords: classification.matched_keywords,
  response_preview: agentResponse.substring(0, 200),
  full_response: agentResponse
};

return [
  {
    json: {
      routing: logEntry,
      response: agentResponse
    }
  }
];
